/// <summary>
/// Data contract for the @TaxTransactionInquiry:HeaderNote report.
/// Defines dialog parameters shown to the user before report execution.
/// </summary>
[DataContractAttribute]
public class ConDemoNoteReportAdvContract
{
    str subjectFilter;

}

Method.Source:
/// <summary>
/// Gets or sets the subjectFilter parameter.
/// </summary>
/// <param name="_subjectFilter">The subjectFilter value.</param>
/// <returns>The current subjectFilter value.</returns>
[DataMemberAttribute('subjectFilter'),
SysOperationLabelAttribute('@TaxTransactionInquiry:HeaderNote')]
public str parmSubjectFilter(str _subjectFilter = subjectFilter)
{
    subjectFilter = _subjectFilter;
    return subjectFilter;
}
